var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……후우.","JPN":"……ふう。","ENG":"…Whew.","TWN":"……呼呼。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……모의 훈련 시스템 가동!","JPN":"……模擬訓練システム、稼働！","ENG":"...Activating simulation training system!","TWN":"……模擬訓練系統啟動！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>조디악 나이츠, 모의 훈련 시스템 가동 완료. </color>","JPN":"<color=#ffd34c>ゾディアックナイツ、模擬訓練システム稼働完了。</color>","ENG":"<color=#ffd34c>Zodiac Knights, simulation training system activation completed. </color>","TWN":"<color=#ffd34c>十二宮騎士團，模擬訓練系統啟動完畢。</color>"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……사용자. 블루시프트, 피오네 로웰.","JPN":"……使用者。ブルーシフト、フィオネ・ローウェル。","ENG":"...User: Blue Shift, Fione Lowell.","TWN":"……使用人 藍移 菲奧尼。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>성문 인식, 성공하였습니다. </color>","JPN":"<color=#ffd34c>声紋認識に成功しました。</color>","ENG":"<color=#ffd34c>Voice recognition succeeded. </color>","TWN":"<color=#ffd34c>語音辨識，成功。</color>"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>환영합니다, 피오네 로웰. </color>","JPN":"<color=#ffd34c>ようこそ、フィオネ・ローウェル。</color>","ENG":"<color=#ffd34c>Welcome, Fione Lowell. </color>","TWN":"<color=#ffd34c>歡迎你，菲奧尼。</color>"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……훈련 설정. 방패 파괴 훈련 5단계.","JPN":"……訓練設定。盾破壊訓練5段階。","ENG":"...Select training: Shield Destruction Training Level 5.","TWN":"……設定訓練，盾牌破壞訓練第5階段。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>……훈련 확인. 홀로그래픽 실드 레벨 5 생성합니다. </color>","JPN":"<color=#ffd34c>……訓練確認。ホログラフィックシールド、レベル5を生成します。</color>","ENG":"<color=#ffd34c>...Training selection confirmed. Generating a Level 5 holographic shield... </color>","TWN":"<color=#ffd34c>……訓練確認。形成5級全像攝影護盾。</color>"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"좋아, 오늘에야말로.","JPN":"よし、今日こそ……","ENG":"Alright, let's do this.","TWN":"很好，就是今天。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"STALKER_COUNTERCASE_NULL","text":{"KOREA":"피오네, 겨우 이런 것도 똑바로 못하는 거야?","JPN":"フィオネ、こんなこともちゃんとできないの？","ENG":"Fione, why can't you even do this?","TWN":"菲奧尼，你連這個也做不好嗎？"},"stage":{"bg":"MANSION","slots":{"L":null,"C":{"char_id":"STALKER_COUNTERCASE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"STALKER_COUNTERCASE_NULL","text":{"KOREA":"하여간 넌 정말, 로웰 가의 수치라니까.","JPN":"まったく、だからあんたは本当にローウェル家の恥なのよ。","ENG":"Seriously, you're a disgrace to our family.","TWN":"你真是勞威爾家族之恥！"},"stage":{"bg":"MANSION","slots":{"L":null,"C":{"char_id":"STALKER_COUNTERCASE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"아니, 이젠 옛날과는 달라.","JPN":"いや、今は昔と違う。","ENG":"No, not anymore.","TWN":"不是，我現在和以前不一樣了。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……간다!!","JPN":"……行くぞ！","ENG":"...Here I go!","TWN":"……來吧！！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"……피오네. 가문을 대표하는 기사가 되었으니 앞으로는 더욱 정진해야 할 거다.","JPN":"……フィオネ。家門を代表する騎士となったからには、これからもっと精進しなければならない。","ENG":"...Fione. Now that you've become the Knight of the family, you must work harder.","TWN":"……菲奧尼，既然你已經是代表家族的騎士，以後必須要更努力。"},"stage":{"bg":"MANSION","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"이 애비는 이번 단장이 로웰 가문에서 나올 거라 믿어 의심치 않는다.","JPN":"父は、今度の団長がローウェル家から出ると信じている。","ENG":"I expect the next captain to be a Lowell.","TWN":"爸爸相信，新任的團長一定是出自我們勞威爾家族。"},"stage":{"bg":"MANSION","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"……잘할 수 있겠지?","JPN":"……やれるな？","ENG":"...You won't disappoint me, will you?","TWN":"……你辦得到吧？"},"stage":{"bg":"MANSION","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"L51_1","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"L51_1","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};